def detect_infinite_loop(agent):
    messages = agent.chat_messages
    if len(messages) < 10:
        return False

    recent = messages[-10:]
    patterns = []
    for i in range(len(recent)-5):
        pattern = tuple(recent[i:i+5])
        patterns.append(pattern)

    if patterns.count(patterns[0]) > 2:
        return {'alert': 'INFINITE_LOOP', 'loop_length': 5, 'confidence': 0.95}
    return False

import re

def detect_unsafe_code(last_message):
    if 'code' not in last_message:
        return False

    code = last_message['content']
    dangerous_patterns = [
        r'rm\s+-rf',
        r'os\.system\(',
        r'subprocess\.run\(.*?shell=True',
        r'exec\(.*?dangerous',
    ]

    for pattern in dangerous_patterns:
        if re.search(pattern, code, re.IGNORECASE):
            return {'alert': 'UNSAFE_CODE', 'pattern': pattern, 'confidence': 0.98}
    return False

def detect_token_exhaustion(groupchat):
    total_messages = sum(len(agent.chat_messages) for agent in groupchat.agents)
    estimated_tokens = total_messages * 200  # avg 200 tokens/message

    if total_messages > 100:
        return {
            'alert': 'TOKEN_EXHAUSTION',
            'message_count': total_messages,
            'estimated_cost': f'${estimated_tokens * 0.00002:.2f}',
            'confidence': min(total_messages/200, 1.0)
        }
    return False

